diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..9759e2919dee 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1139,24 +1139,48 @@ Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *X, *MulOpV;
   APInt C0, MulOpC;
   bool IsSigned;
-  // Match I = X % C0 + MulOpV * C0
-  if (((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
-       (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) &&
-      C0 == MulOpC) {
-    Value *RemOpV;
-    APInt C1;
-    bool Rem2IsSigned;
-    // Match MulOpC = RemOpV % C1
-    if (MatchRem(MulOpV, RemOpV, C1, Rem2IsSigned) &&
-        IsSigned == Rem2IsSigned) {
-      Value *DivOpV;
-      APInt DivOpC;
-      // Match RemOpV = X / C0
-      if (MatchDiv(RemOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
-          C0 == DivOpC && !MulWillOverflow(C0, C1, IsSigned)) {
-        Value *NewDivisor = ConstantInt::get(X->getType(), C0 * C1);
-        return IsSigned ? Builder.CreateSRem(X, NewDivisor, "srem")
-                        : Builder.CreateURem(X, NewDivisor, "urem");
+  // Match I = X % C0 + MulOpV * MulOpC
+  if ((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
+      (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) {
+    if (C0 == MulOpC) {
+      Value *RemOpV;
+      APInt C1;
+      bool Rem2IsSigned;
+      // Match MulOpC = RemOpV % C1
+      if (MatchRem(MulOpV, RemOpV, C1, Rem2IsSigned) &&
+          IsSigned == Rem2IsSigned) {
+        Value *DivOpV;
+        APInt DivOpC;
+        // Match RemOpV = X / C0
+        if (MatchDiv(RemOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+            C0 == DivOpC && !MulWillOverflow(C0, C1, IsSigned)) {
+          Value *NewDivisor = ConstantInt::get(X->getType(), C0 * C1);
+          return IsSigned ? Builder.CreateSRem(X, NewDivisor, "srem")
+                          : Builder.CreateURem(X, NewDivisor, "urem");
+        }
+      }
+    }
+
+    Value *DivOpV;
+    APInt DivOpC;
+    // Match MulOpV = X / C0
+    if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+        C0 == DivOpC) {
+      if (!isGuaranteedNotToBePoison(X))
+        return nullptr;
+      if (!MulOpV->hasOneUse() && !LHS->hasOneUse() && !RHS->hasOneUse())
+        return nullptr;
+      if (MulOpC == C0)
+        return X;
+      // X % C0 + (X / C0) * MulOpC -> X + (X / C0) * (MulOpC - C0)
+      if (MulOpC.sge(C0) || !IsSigned) {
+        if (!MulOpV->hasOneUse()) return nullptr;
+        if (I.hasNoUnsignedWrap() && I.hasNoSignedWrap()) return nullptr;
+        Value *NewMul = Builder.CreateMul(MulOpV, ConstantInt::get(X->getType(), MulOpC - C0), "reass.mul");
+        if (auto *BO = dyn_cast<BinaryOperator>(NewMul)) {
+          if (!IsSigned) BO->setHasNoUnsignedWrap(true);
+        }
+        return Builder.CreateAdd(X, NewMul);
       }
     }
   }
